import { ipcMain, app } from 'electron';
import { IPC_CHANNELS, GetSettingSchema, SetSettingSchema, SetMaxLogLinesSchema, ApiResult } from './types';
import { queries } from '../db';
import { appPreferences } from '../services/AppPreferences';

export function registerSettingsHandlers() {
  // Get app version
  ipcMain.handle(IPC_CHANNELS.APP_GET_VERSION, async (): Promise<ApiResult<string>> => {
    try {
      const version = app.getVersion();
      return { success: true, data: version };
    } catch (error) {
      console.error('Error getting app version:', error);
      return { success: false, error: String(error) };
    }
  });

  // Get a setting
  ipcMain.handle(IPC_CHANNELS.SETTINGS_GET, async (_event, input): Promise<ApiResult<string | null>> => {
    try {
      const { key } = GetSettingSchema.parse(input);
      const setting = queries.getSetting(key);
      return { success: true, data: setting?.value || null };
    } catch (error) {
      console.error('Error getting setting:', error);
      return { success: false, error: String(error) };
    }
  });

  // Set a setting
  ipcMain.handle(IPC_CHANNELS.SETTINGS_SET, async (_event, input): Promise<ApiResult<void>> => {
    try {
      const { key, value } = SetSettingSchema.parse(input);
      queries.setSetting(key, value);
      return { success: true };
    } catch (error) {
      console.error('Error setting setting:', error);
      return { success: false, error: String(error) };
    }
  });

  // Get all app preferences
  ipcMain.handle(IPC_CHANNELS.APP_PREFERENCES_GET, async (): Promise<ApiResult<{ maxDeploymentLogLines: number }>> => {
    try {
      const maxDeploymentLogLines = appPreferences.getMaxDeploymentLogLines();
      return { success: true, data: { maxDeploymentLogLines } };
    } catch (error) {
      console.error('Error getting app preferences:', error);
      return { success: false, error: String(error) };
    }
  });

  // Get max deployment log lines
  ipcMain.handle(IPC_CHANNELS.APP_PREFERENCES_GET_MAX_LOG_LINES, async (): Promise<ApiResult<number>> => {
    try {
      const maxLines = appPreferences.getMaxDeploymentLogLines();
      return { success: true, data: maxLines };
    } catch (error) {
      console.error('Error getting max log lines:', error);
      return { success: false, error: String(error) };
    }
  });

  // Set max deployment log lines
  ipcMain.handle(IPC_CHANNELS.APP_PREFERENCES_SET_MAX_LOG_LINES, async (_event, input): Promise<ApiResult<void>> => {
    try {
      const { lines } = SetMaxLogLinesSchema.parse(input);
      appPreferences.setMaxDeploymentLogLines(lines);
      return { success: true };
    } catch (error) {
      console.error('Error setting max log lines:', error);
      return { success: false, error: String(error) };
    }
  });
}
